import React, { useState, useEffect } from 'react';
import { View, Text, Button, NetInfo } from 'react-native';

const generateToken = () => {
  return 'token_' + Math.random().toString(36).substr(2, 16);
};

const TokenGenerator = () => {
  const [offlineTokens, setOfflineTokens] = useState([]);
  const [isConnected, setIsConnected] = useState(true);

  useEffect(() => {
    const handleConnectivityChange = (connectionInfo) => {
      setIsConnected(connectionInfo.isConnected);
    };

    NetInfo.addEventListener(handleConnectivityChange);
    return () => {
      NetInfo.removeEventListener(handleConnectivityChange);
    };
  }, []);

  const handleGenerateToken = () => {
    const newToken = generateToken();
    setOfflineTokens([...offlineTokens, newToken]);
  };

  return (
    <View>
      {isConnected ? (
        <Text>You are online</Text>
      ) : (
        <View>
          <Text>You are offline</Text>
          <Button title="Generate Token" onPress={handleGenerateToken} />
          {offlineTokens.map((token, index) => (
            <Text key={index}>{token}</Text>
          ))}
        </View>
      )}
    </View>
  );
};

export default TokenGenerator;